(function() {
  /*
   * PATCH v1.1.0 — Energy cost when traveling to other lands
   *
   * Cost table (energy drained on arrival):
   *   home      ->  0  (always free)
   *   meadow    -> 10
   *   riverbank -> 15
   *   hillfarm  -> 20
   *   lowland   -> 25
   *   volcanic  -> 35  (most prestigious, most tiring)
   *
   * Respects the Energy Cost toggle in Options/Pause menu.
   * Blocks travel if the player lacks enough energy.
   */
  var TRAVEL_ENERGY = {
    home: 0,
    meadow: 10,
    riverbank: 15,
    hillfarm: 20,
    lowland: 25,
    volcanic: 35
  };

  var _origTravelTo = window.travelTo;

  window.travelTo = function(landId) {
    if (landId === G.currentLand) { _origTravelTo(landId); return; }

    if (S.energyCost) {
      var cost = (TRAVEL_ENERGY[landId] !== undefined) ? TRAVEL_ENERGY[landId] : 15;

      if (cost > 0) {
        if (G.energy < cost) {
          toast(
            'Not enough energy to travel! Need ' + cost + ' energy — sleep first. 🌙',
            'error',
            3500
          );
          snd('error');
          return;
        }

        G.energy = Math.max(0, G.energy - cost);
        if (typeof renderHUD === 'function') renderHUD();

        setTimeout(function() {
          var el = document.getElementById('tp-sub');
          if (el) el.textContent = '⚡ Used ' + cost + ' energy for the journey…';
        }, 80);
      }
    }

    _origTravelTo(landId);
  };

  console.log('[Patcher v1.1.0] Travel energy cost patch applied.');

  /*
   * PATCH v1.1.1a — Bag button & swipe-up always open the Bag (inv) tab first
   *
   * Previously the sheet/side panel remembered whatever tab was last active
   * (defaulting to "Upgrades" on first load). Now pressing the 🎒 Bag button
   * or swiping up on mobile always switches to the Bag tab before opening.
   */
  var _origToggleBag = window.toggleBag;
  window.toggleBag = function() {
    window.setTab('inv');
    _origToggleBag();
  };

  var _origOpenSheet = window.openSheet;
  window.openSheet = function() {
    window.setTab('inv');
    _origOpenSheet();
  };

  console.log('[Patcher v1.1.1a] Bag default-tab patch applied.');

  /*
   * PATCH v1.1.1b — Mobile map fullscreen: map visual on top, land list below
   *
   * On small screens the original two-column PC layout stacks with land cards
   * on top and the map buried at the bottom. This patch detects mobile widths
   * (≤ 680 px) and rebuilds the map screen so the SVG map fills the top of
   * the overlay and the scrollable land options sit underneath it.
   */
  var _origBuildMapFullscreen = window.buildMapFullscreen;
  window.buildMapFullscreen = function() {
    if (window.innerWidth > 680) {
      _origBuildMapFullscreen();
      return;
    }

    var body = document.getElementById('mf-body');
    var owned = G.lands || {};

    var totalRentPerDay = Object.entries(owned).reduce(function(s, e) {
      var id = e[0], l = e[1];
      if (l.rented && !l.owned) {
        var p = LAND_PLOTS[id];
        return s + (p ? Math.round(p.rentDay * (1 + (l.interestAccrued || 0))) : 0);
      }
      return s;
    }, 0);

    var rentEl = document.getElementById('mf-rent-info');
    if (rentEl) rentEl.textContent = totalRentPerDay > 0 ? '⏳ Rent: ' + totalRentPerDay + 'g/day' : '';

    /* ── Map visual (top, full-width, tall aspect ratio) ── */
    var mapVisualHtml =
      '<div style="position:relative;width:100%;aspect-ratio:16/9;border-radius:12px;overflow:hidden;border:2px solid var(--ui-border)">' +
      buildMapSVG(owned, false) +
      '</div>';

    /* ── Land cards (below map) ── */
    var landHtml = '';
    if ((G.currentLand || 'home') !== 'home') {
      landHtml += '<button class="map-return-btn" onclick="travelTo(\'home\')">🏡 Return to Home Farm</button>';
    }
    landHtml += '<div class="s-sec" style="margin-top:12px">🗺 Available Land</div>';

    if (totalRentPerDay > 0) {
      landHtml +=
        '<div style="padding:7px 10px;background:#fef9c3;border:1px solid #fde68a;border-radius:10px;font-size:10px;font-weight:700;color:#92400e;margin-bottom:8px">' +
        '⏳ Active rent: <b>' + totalRentPerDay + 'g/day</b> deducted each night</div>';
    }

    var dangerPlots = Object.entries(owned).filter(function(e) {
      return e[1].rented && !e[1].owned && (e[1].debtDays || 0) >= 5;
    });
    if (dangerPlots.length) {
      landHtml +=
        '<div class="mf-debt-warning">🚨 <b>DANGER!</b> ' + dangerPlots.length +
        ' plot(s) have missed rent for 5+ days! Pay up before day 7 or crops will be seized!</div>';
    }

    Object.entries(LAND_PLOTS).forEach(function(entry) {
      var id = entry[0], plot = entry[1];
      var land = owned[id] || {};
      var isOwned  = land.owned;
      var isRented = land.rented && !land.owned;
      var effectiveRent = isRented
        ? Math.round(plot.rentDay * (1 + (land.interestAccrued || 0)))
        : plot.rentDay;
      var hasDebt  = (land.debtG || 0) > 0;
      var debtDays = land.debtDays || 0;
      var fertClass = plot.fertility.toLowerCase();

      landHtml +=
        '<div class="land-card">' +
          '<div class="land-card-top"><div class="land-card-left">' +
            '<span class="land-em">' + plot.e + '</span>' +
            '<div><div class="land-name">' + plot.n +
              ' <span class="land-fert ' + fertClass + '">' + plot.fertility + '</span>' +
            '</div></div>' +
          '</div></div>' +
          '<div class="land-desc">' + plot.desc + '</div>' +
          '<div class="land-price-row">' +
            '<span class="land-price-tag">💰 Buy: ' + plot.buyPrice + 'g</span>' +
            '<span class="land-rent-tag">· Rent: ' + plot.rentDay + 'g/day</span>' +
            '<span class="land-interest-tag">(+' + Math.round(plot.interestRate * 100) + '% interest/season)</span>' +
          '</div>';

      if (isOwned) {
        landHtml +=
          '<span class="land-owned-badge">✓ You own this land</span>' +
          '<div class="land-btn-row">' +
            '<button class="land-btn map-travel-btn" onclick="travelTo(\'' + id + '\')">🚀 Go to this Farm</button>' +
          '</div>';
      } else if (isRented) {
        var debtWarning = debtDays > 0 ? ' · ⏰ ' + (7 - debtDays) + 'd left' : '';
        landHtml +=
          '<span class="land-rented-badge">⏳ Renting · ' + effectiveRent + 'g/day' +
            (hasDebt ? ' · ⚠️ Debt: ' + Math.round(land.debtG) + 'g' + debtWarning : '') +
          '</span>' +
          '<div class="land-btn-row">' +
            '<button class="land-btn land-btn-buy" id="mfbl-' + id + '" ' + (G.gold >= plot.buyPrice ? '' : 'disabled') + '>Buy Out ' + plot.buyPrice + 'g</button>' +
            '<button class="land-btn land-btn-leave" id="mfll-' + id + '">Leave Plot</button>' +
            '<button class="land-btn map-travel-btn" onclick="travelTo(\'' + id + '\')">🚀 Go Here</button>' +
          '</div>';
      } else {
        landHtml +=
          '<div class="land-btn-row">' +
            '<button class="land-btn land-btn-buy" id="mfbl-' + id + '" ' + (G.gold >= plot.buyPrice ? '' : 'disabled') + '>Buy ' + plot.buyPrice + 'g</button>' +
            '<button class="land-btn land-btn-rent" id="mfrl-' + id + '" ' + (G.gold >= plot.rentDay ? '' : 'disabled') + '>Rent ' + plot.rentDay + 'g/day</button>' +
          '</div>';
      }
      landHtml += '</div>';
    });

    landHtml +=
      '<div class="market-note" style="margin-top:8px;margin-bottom:20px">' +
      '💡 <b>Land Tips:</b><br>Owned land is yours permanently. Rented land charges daily — miss 7 days\' rent and crops get seized by the landlord! Leave a rented plot anytime, debt forgiven.</div>';

    /* ── Assemble: map on top, land list below (both in a scrollable column) ── */
    body.style.overflowY = 'auto';
    body.innerHTML =
      '<div style="padding:12px 12px 8px">' + mapVisualHtml + '</div>' +
      '<div style="padding:0 12px 16px">' + landHtml + '</div>';

    /* ── Re-bind buy / rent / leave buttons ── */
    Object.keys(LAND_PLOTS).forEach(function(id) {
      var bl = document.getElementById('mfbl-' + id);
      var rl = document.getElementById('mfrl-' + id);
      var ll = document.getElementById('mfll-' + id);
      if (bl) bl.addEventListener('click', function() { buyLand(id);  buildMapFullscreen(); });
      if (rl) rl.addEventListener('click', function() { rentLand(id); buildMapFullscreen(); });
      if (ll) ll.addEventListener('click', function() { leaveLand(id); buildMapFullscreen(); });
    });
  };

  console.log('[Patcher v1.1.1b] Mobile map layout patch applied.');
})();
